import { match } from "arktype";

/**
 * Match-based event router built with ArkType 2.2.0.
 *
 * Cases (in order):
 *  1. bare string          → "text:<length>"
 *  2. bare number          → "num:<value>"
 *  3. string[]             → "list:<length>"
 *  4. click / button       → "btn:<target.id>"
 *  5. click / link         → "link:<target.href>"  (href must be a valid URL)
 *  6. submit               → "submit:<formId>:<valid>"
 *  default: "assert"       → throws TraversalError for anything else
 */
export const route = match({
  // ── 1. bare string ────────────────────────────────────────────────────────
  string: (s) => `text:${s.length}`,

  // ── 2. bare number ────────────────────────────────────────────────────────
  number: (n) => `num:${n}`,

  // ── 3. string array ───────────────────────────────────────────────────────
  "string[]": (arr) => `list:${arr.length}`,

  // ── 4. click event – button target ────────────────────────────────────────
  "{ kind: 'click', target: { type: 'button', id: string } }": (e) =>
    `btn:${e.target.id}`,

  // ── 6. submit event ───────────────────────────────────────────────────────
  "{ kind: 'submit', payload: { formId: string, valid: boolean } }": (e) =>
    `submit:${e.payload.formId}:${e.payload.valid}`,

  // ── default: throw TraversalError ─────────────────────────────────────────
  default: "assert",
})
  // ── 5. click event – link target (href validated as URL) ──────────────────
  //    Uses the fluent .case() API so we can reference the `string.url` keyword
  //    that is not easily embedded inside an object-literal key.
  .case(
    "{ kind: 'click', target: { type: 'link', href: string.url } }",
    (e) => `link:${e.target.href}`,
  );

