import { match } from "arktype";

/**
 * Match-based event router built with ArkType 2.2.0.
 *
 * Cases (in order):
 *  1. bare string          → "text:<length>"
 *  2. bare number          → "num:<value>"
 *  3. string[]             → "list:<length>"
 *  4. click / button       → "btn:<target.id>"
 *  5. click / link         → "link:<target.href>"  (href must be a valid URL)
 *  6. submit               → "submit:<formId>:<valid>"
 *  default: "assert"       → throws TraversalError for anything else
 */
export const route = match({
  // ── 1. bare string ────────────────────────────────────────────────────────
  string: (s) => `text:${s.length}`,

  // ── 2. bare number ────────────────────────────────────────────────────────
  number: (n) => `num:${n}`,

  // ── 3. string array ───────────────────────────────────────────────────────
  "string[]": (arr) => `list:${arr.length}`,

  // ── 4. click event – button target ────────────────────────────────────────
  //    Discriminates on kind === 'click' AND target.type === 'button'
  "{ kind: 'click', target: { type: 'button', id: string } }": (e) =>
    `btn:${e.target.id}`,

  // ── 6. submit event ───────────────────────────────────────────────────────
  //    Discriminates on kind === 'submit' with a formId string and valid bool
  "{ kind: 'submit', payload: { formId: string, valid: boolean } }": (e) =>
    `submit:${e.payload.formId}:${e.payload.valid}`,
})
  // ── 5. click event – link target (href validated as URL via string.url) ───
  //    Uses the fluent .case() API because string.url is a keyword, not a
  //    literal type that can be embedded in an object-literal string key easily.
  //    Discriminates on kind === 'click' AND target.type === 'link'.
  .case(
    "{ kind: 'click', target: { type: 'link', href: string.url } }",
    (e) => `link:${e.target.href}`,
  )
  // ── default: throw TraversalError for any unmatched event ─────────────────
  .default("assert");

import { TraversalError } from "arktype";
import { route } from "./src/router.ts";

// ── Read all of stdin ──────────────────────────────────────────────────────
const chunks: Buffer[] = [];
for await (const chunk of process.stdin) {
  chunks.push(chunk as Buffer);
}
const raw = Buffer.concat(chunks).toString("utf8");

// ── Parse the top-level JSON document ─────────────────────────────────────
let doc: { events: unknown[] };
try {
  const parsed = JSON.parse(raw) as unknown;
  if (
    typeof parsed !== "object" ||
    parsed === null ||
    !Array.isArray((parsed as Record<string, unknown>).events)
  ) {
    process.stdout.write(
      `ERR input must be an object with an "events" array\n`,
    );
    process.exit(0);
  }
  doc = parsed as { events: unknown[] };
} catch (err) {
  process.stdout.write(`ERR failed to parse JSON: ${String(err)}\n`);
  process.exit(0);
}

// ── Dispatch each event through the router ────────────────────────────────
for (const event of doc.events) {
  try {
    const result = route(event as never);
    process.stdout.write(`${result}\n`);
  } catch (err) {
    // TraversalError is thrown by the "assert" default when no case matches.
    // Print the ERR line and stop – exit code is always 0.
    if (err instanceof TraversalError) {
      process.stdout.write(`ERR ${err.message}\n`);
    } else {
      process.stdout.write(`ERR ${String(err)}\n`);
    }
    process.exit(0);
  }
}

import { match, type } from "arktype";

/**
 * Match-based event router built with ArkType 2.2.0.
 *
 * Cases (in order):
 *  1. bare string          → "text:<length>"
 *  2. bare number          → "num:<value>"
 *  3. string[]             → "list:<length>"
 *  4. click / button       → "btn:<target.id>"
 *  5. click / link         → "link:<target.href>"  (href validated as string.url)
 *  6. submit               → "submit:<formId>:<valid>"
 *  default: "assert"       → throws TraversalError for any unmatched event
 *
 * Cases 1-3 use the object-literal shorthand (primitive/array type strings are
 * embeddable as record keys).  Cases 4-6 use the fluent .case() API because
 * object shapes cannot be embedded as record-key strings in the match() call.
 */
export const route = match({
  // ── 1. bare string ────────────────────────────────────────────────────────
  string: (s) => `text:${s.length}`,

  // ── 2. bare number ────────────────────────────────────────────────────────
  number: (n) => `num:${n}`,

  // ── 3. string array ───────────────────────────────────────────────────────
  "string[]": (arr) => `list:${arr.length}`,
})
  // ── 4. click event – button target ────────────────────────────────────────
  //    Discriminates on kind === 'click' AND target.type === 'button'
  .case(
    type({
      kind: "'click'",
      target: { type: "'button'", id: "string" },
    }),
    (e) => `btn:${e.target.id}`,
  )
  // ── 5. click event – link target ──────────────────────────────────────────
  //    Discriminates on kind === 'click' AND target.type === 'link'.
  //    href must be a syntactically valid URL (ArkType keyword: string.url).
  .case(
    type({
      kind: "'click'",
      target: { type: "'link'", href: "string.url" },
    }),
    (e) => `link:${e.target.href}`,
  )
  // ── 6. submit event ───────────────────────────────────────────────────────
  //    Discriminates on kind === 'submit' with a formId string and valid bool
  .case(
    type({
      kind: "'submit'",
      payload: { formId: "string", valid: "boolean" },
    }),
    (e) => `submit:${e.payload.formId}:${e.payload.valid}`,
  )
  // ── default: throw TraversalError for any unmatched event ─────────────────
  .default("assert");

